from pydantic_ai import Agent
from vex_sdk import VexResultValidator

# Detect validator rejections
@Agent.tool
def detect_validation_failures(response: str) -> dict:
    try:
        return {'status': 'valid', 'content': response}
    except ValidationError as e:
        print(f'VALIDATION FAILED: {e}')
        return {'status': 'rejected'}

agent = Agent(tools=[detect_validation_failures])
result = agent.run('analyze this data')

from pydantic_ai import Agent, Context
from contextlib import contextmanager

@contextmanager
def trace_context(ctx: Context):
    print(f'ENTER CONTEXT: {ctx.user_id}')
    try:
        yield ctx
    except Exception as e:
        print(f'CONTEXT LOST: {e}')
        raise

agent = Agent(context_tracer=trace_context)
result = agent.run('nested tool workflow')
